#include "pytorch_npu_helper.hpp"

at::Tensor conv_transposed_1d_dilated_impl_npu(const at::Tensor& x,
                                               const at::Tensor& weight,
                                               int64_t stride,
                                               int64_t padding,
                                               int64_t dilation) {
    // Infer output shape: (N, Cout, Lout)
    TORCH_CHECK(x.dim() == 3 && weight.dim() == 3, \"Expected 3D x and weight\");
    const int64_t N   = x.size(0);
    const int64_t Cin = x.size(1);
    const int64_t Lin = x.size(2);
    const int64_t W_Cin = weight.size(0);
    const int64_t Cout  = weight.size(1);
    const int64_t K     = weight.size(2);
    TORCH_CHECK(Cin == W_Cin, \"Input channels mismatch\");
    const int64_t Lout = (Lin - 1) * stride - 2 * padding + dilation * (K - 1) + 1;
    TORCH_CHECK(Lout > 0, \"Invalid output length\");

    at::Tensor y = at::empty({N, Cout, Lout}, x.options());
    EXEC_NPU_CMD(aclnnConvTransposed1dDilatedCustom, x, weight,
                 static_cast<int>(stride),
                 static_cast<int>(padding),
                 static_cast<int>(dilation),
                 y);
    return y;
